INSERT INTO articles (id, title, slug, lead, content, category_id, status, published_at, views) VALUES
(
  'a4000000-0000-4000-a000-000000000001',
  'В горной Ингушетии начались раскопки древнего поселения возрастом более трёх тысяч лет',
  'v-gornoj-ingushetii-raskopki-drevnego-poseleniya-3000-let',
  'Археологи приступили к извлечению построек, обнаруженных под землёй вблизи средневекового башенного комплекса Гирети на высоте 1500 метров.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В горной Ингушетии начались раскопки древнего поселения, обнаруженного в 2025 году под землёй вблизи средневекового башенного комплекса Гирети. Об этом сообщил руководитель школы каменщиков-реставраторов «Наследие» Рамзан Султыгов."}]},{"type":"paragraph","content":[{"type":"text","text":"Постройки, которым предположительно три с половиной тысячи лет, были найдены на высоте полутора тысяч метров над уровнем моря. Исследователей поразили гладко обтёсанные каменные глыбы, сложенные вместе без соединительного раствора — методом сухой кладки."}]},{"type":"paragraph","content":[{"type":"text","text":"Учёные полагают, что это было жилое поселение. Сейчас ведутся работы по извлечению строений из-под земли. По словам Султыгова, в будущем возможна их реставрация. Сам башенный комплекс Гирети, рядом с которым обнаружены находки, появился на этом месте предположительно в XVI веке."}]},{"type":"paragraph","content":[{"type":"text","text":"Территория расположена в Галгаевском ущелье — историческом месте формирования этнического ядра ингушского народа. Ранее здесь уже находили сооружения циклопической кладки II тысячелетия до нашей эры. Новые находки могут подтвердить гипотезу о существовании на этой территории крупного древнего поселения."}]}]}',
  'c1000000-0000-4000-a000-000000000008',
  'published',
  '2026-04-08T14:00:00Z',
  203
),
(
  'a4000000-0000-4000-a000-000000000002',
  'Мовсар Евлоев рассказал о детстве в Ингушетии и пути к вершине UFC',
  'movsar-evloev-rasskazal-o-detstve-v-ingushetii-i-ufc',
  'Непобеждённый боец UFC из Сунжи дал интервью о первых шагах в спорте и предстоящем титульном бою.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Непобеждённый боец UFC, уроженец Сунжи Мовсар Евлоев дал развёрнутое интервью, в котором рассказал о детстве в Ингушетии, первых занятиях спортом и сложном пути к вершине мирового MMA."}]},{"type":"paragraph","content":[{"type":"text","text":"32-летний спортсмен откровенно поделился воспоминаниями о непростом детстве в республике и о том, как спорт изменил его жизнь. На его счету 20 побед в 20 профессиональных поединках и серия из 10 побед подряд в UFC."}]},{"type":"paragraph","content":[{"type":"text","text":"В марте 2026 года Евлоев одержал очередную победу на турнире UFC Fight Night 270 в Лондоне, досрочно остановив британца Лерона Мерфи. Ожидается, что ингушский боец станет следующим претендентом на титул чемпиона и встретится с действующим обладателем пояса австралийцем Алексом Волкановски."}]},{"type":"paragraph","content":[{"type":"text","text":"Мовсар Евлоев — один из самых успешных ингушских спортсменов на мировой арене и пример для подрастающего поколения республики."}]}]}',
  'c1000000-0000-4000-a000-000000000005',
  'published',
  '2026-04-08T12:00:00Z',
  178
),
(
  'a4000000-0000-4000-a000-000000000003',
  'Власти Ингушетии обещают устранить все паводковые зоны до конца апреля',
  'vlasti-ingushetii-ustranyat-pavodkovye-zony-do-konca-aprelya',
  'Министр экологии Микаил Мизиев заявил о создании дорожной карты потенциально опасных участков и начале дноуглубительных работ.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Власти Ингушетии намерены до конца апреля устранить все опасные паводковые зоны в республике. Об этом заявил министр природных ресурсов и экологии Микаил Мизиев."}]},{"type":"paragraph","content":[{"type":"text","text":"По словам министра, сейчас создаётся дорожная карта потенциально опасных точек региона, где большая вода принесла каменные наносы. На выявленных участках будут проводиться дноуглубительные работы за счёт собственных ресурсов. Для координации работ создана специальная рабочая группа с участием глав городов и сёл."}]},{"type":"paragraph","content":[{"type":"text","text":"Напомним, 28–29 марта в Ингушетии выпали обильные осадки. Уровень воды в реке Сунже поднялся до 3 метров. Особенно сложная ситуация сложилась в Сунже, Карабулаке и Троицком. 5 апреля в Троицком в результате дождей обвалилась часть дороги вдоль берега реки, были подтоплены дома и автодороги."}]},{"type":"paragraph","content":[{"type":"text","text":"Мизиев подчеркнул, что сезон паводков продлится до конца мая и медлить нельзя — необходимо провести первоочередные защитные мероприятия до начала крупных дождей."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-04-08T10:00:00Z',
  94
),
(
  'a4000000-0000-4000-a000-000000000004',
  'В Сунже начали реконструкцию рынка, сгоревшего весной 2025 года',
  'v-sunzhe-nachali-rekonstrukciyu-rynka-sgorevshego-2025',
  'Строители ведут заливку фундамента под новые павильоны. При пожаре без работы остались более 50 предпринимателей.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Сунже начались работы по реконструкции рынка, сгоревшего при пожаре в мае 2025 года. По данным правительства Ингушетии, строители уже ведут заливку фундамента под новые павильоны, ранее на объекте построили ливневый канал, обновили фасады и крыши торговых павильонов."}]},{"type":"paragraph","content":[{"type":"text","text":"В результате пожара без рабочих мест остались более 50 предпринимателей. На территории, охваченной огнём, находилось 220 торговых точек, из которых только 134 были зарегистрированы в налоговой."}]},{"type":"paragraph","content":[{"type":"text","text":"Глава республики Махмуд-Али Калиматов, посетивший место ЧП в 2025 году, раскритиковал местных чиновников за допущенные нарушения и заявил, что объект не должен был работать из-за несоответствия правилам противопожарной безопасности. Точные сроки полного возобновления работы рынка пока не называются."}]}]}',
  'c1000000-0000-4000-a000-000000000002',
  'published',
  '2026-04-07T15:00:00Z',
  67
),
(
  'a4000000-0000-4000-a000-000000000005',
  'Правительство РФ списало с Ингушетии бюджетные кредиты на 450 миллионов рублей',
  'pravitelstvo-rf-spisalo-s-ingushetii-450-mln-rublej',
  'Премьер-министр Михаил Мишустин включил республику в число 11 регионов, которым списали долги на общую сумму 10 млрд рублей.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Правительство России списало часть задолженности по бюджетным кредитам 11 регионам страны, в том числе Ингушетии. Об этом сообщил премьер-министр Михаил Мишустин. Сумма, списанная с республики, составила 446 миллионов рублей."}]},{"type":"paragraph","content":[{"type":"text","text":"В общей сложности регионам списаны долги на 10 миллиардов рублей. Помимо Ингушетии, мера коснулась Дагестана, Алтая, Тывы, Марий Эл, Забайкальского края, а также Брянской, Кировской, Рязанской, Саратовской и Ульяновской областей."}]},{"type":"paragraph","content":[{"type":"text","text":"Размер списания для каждого региона эквивалентен объёму средств, направленных местными властями на модернизацию ЖКХ, расселение аварийного жилья и реализацию национальных проектов."}]},{"type":"paragraph","content":[{"type":"text","text":"В августе 2025 года с Ингушетии уже списывалась часть долгов. По заявлению главы республики Махмуд-Али Калиматова, общий объём задолженности, предложенной к списанию в 2024–2026 годах, составляет 1,2 миллиарда рублей."}]}]}',
  'c1000000-0000-4000-a000-000000000002',
  'published',
  '2026-04-07T10:00:00Z',
  145
);

